//! BFS model checker for PetersonMutex (generated by tla2 codegen --scaffold).
//!
//! This binary runs a standalone BFS model check over the generated
//! `PetersonMutex` state machine, equivalent to `tla2 check` but operating
//! on compiled Rust code instead of interpreting TLA+.

mod peterson_mutex;

use peterson_mutex::PetersonMutex;
use tla_runtime::prelude::*;

fn main() {
    let machine = PetersonMutex;
    let max_states = 10_000_000;

    println!("Peterson's Mutex -- compiled BFS model checker");
    println!("================================================");
    println!();

    // Run BFS model check with invariant checking
    let result = model_check(&machine, max_states);

    println!("Distinct states: {}", result.distinct_states);
    println!("States explored: {}", result.states_explored);

    if let Some(ref violation) = result.violation {
        eprintln!();
        eprintln!("INVARIANT VIOLATION: {:?}", violation.state);
        if let Some(ref name) = violation.invariant_name {
            eprintln!("Violated invariant: {}", name);
        }
        std::process::exit(1);
    }

    if let Some(ref deadlock) = result.deadlock {
        println!();
        println!("Deadlock detected at state: {:?}", deadlock);
        std::process::exit(1);
    }

    println!();
    if result.is_ok() {
        println!("Model check complete: no errors found.");
        println!(
            "Safety verified: MutualExclusion holds across all {} states.",
            result.distinct_states
        );
    } else {
        std::process::exit(1);
    }
}
